<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> dir </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> input</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;directory&quot;</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">();</span></span>
