<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">map_err</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">e</span><span style="color:#94E2D5;">|</span><span style="color:#89B4FA;font-style:italic;"> format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Failed to execute: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> e</span><span style="color:#9399B2;">))</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
